INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '30aa40fc-a26c-44d8-86c0-2623b7228d86',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bicep State Management — Deployment Stacks Are Your terraform.tfstate$escape$,
  $escape$Bicep doesn't use a state file — Azure Resource Manager is the backend. ARM tracks deployed resource properties natively, so every `az deployment group create` compares your template against live resource state. But for lifecycle control over orphaned resources and drift prevention, Deployment Stacks are Bicep's answer to Terraform-style state management.

A stack groups resources under a single tracked unit scoped to a resource group or subscription. When you remove a resource from your Bicep file and redeploy the stack, `--action-on-unmanage deleteResources` instructs ARM to delete the detached resource automatically — no manual cleanup, no orphan sprawl.

For locking, stacks support `--deny-settings-mode denyWritesAndDeletes` at the stack level, blocking out-of-band writes without scattering `Microsoft.Authorization/locks` resources across templates. `--deny-settings-apply-to-child-scopes` extends protection to nested resource groups.

Stack state lives entirely in ARM — query it with `az stack group show` to inspect managed resources and their `resourcesCleanupAction` status. This gives you a deterministic, auditable deployment lifecycle with zero external state backend to configure, secure, or version.$escape$,
  $escape$# Create/update a Deployment Stack — Bicep's stateful deployment primitive
az stack group create \
  --name "prod-infra-stack" \
  --resource-group "rg-prod" \
  --template-file "./main.bicep" \
  --parameters ./main.bicepparam \
  --action-on-unmanage deleteResources \
  --deny-settings-mode denyWritesAndDeletes \
  --deny-settings-apply-to-child-scopes \
  --yes

# Inspect managed resource state and cleanup assignments
az stack group show \
  --name "prod-infra-stack" \
  --resource-group "rg-prod" \
  --query "resources[].{id:id,action:resourcesCleanupAction}"$escape$,
  $escape$bash$escape$,
