INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c1064cc7-7597-4a70-a539-2b298a212aa3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bicep Workspaces — One Codebase, Three Environments$escape$,
  $escape$Bicep has no native 'workspace' concept, but parameter files give you the same isolation. Create a `main.bicep` with parameterized resource names, SKUs, and replica counts, then pair it with `dev.bicepparam`, `staging.bicepparam`, and `prod.bicepparam`. Each `.bicepparam` file uses the `using` keyword to bind to the same template, so drift between environments is structurally impossible — you can't accidentally deploy a prod SKU to dev when the SKU is a parameter.

Use `targetScope = 'subscription'` at the top of your main template so all three environments deploy into separate resource groups (`rg-myapp-dev`, `rg-myapp-staging`, `rg-myapp-prod`). Reference the param files directly in your GitHub Actions workflow with `az deployment sub create --parameters dev.bicepparam`. For secrets, never hardcode them in param files — use `getSecret()` inside `.bicepparam` to pull values from a per-environment Key Vault at deploy time. This keeps all environment logic in the param layer and the template itself purely structural.$escape$,
  $escape$// prod.bicepparam
using './main.bicep'

param environmentName = 'prod'
param location = 'eastus'
param appServiceSkuName = 'P2v3'
param minInstanceCount = 3
param keyVaultName = 'kv-myapp-prod'

param sqlAdminPassword = getSecret(
  '11111111-1111-1111-1111-111111111111',
  'rg-myapp-prod',
  'kv-myapp-prod',
  'sql-admin-password'
)$escape$,
  $escape$bash$escape$,
