INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7a85321a-468c-4c46-9535-a41da8cd3396',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bicep — Azure's ARM Replacement with Modules and Typed Parameters$escape$,
  $escape$Bicep compiles down to ARM JSON but writes like a real language. Every `.bicep` file is a first-class ARM template — no state files, no provider plugins, just `az deployment group create`. Parameters are strongly typed: `param sku string = 'Standard_LRS'` enforces type at compile time, and `@allowed(['Standard_LRS', 'Premium_LRS'])` adds ARM-level validation without custom policies.

Modules are the real unlock. A `module storageModule './storage.bicep' = { ... }` call compiles each module into a nested ARM deployment, preserving dependency tracking via `dependsOn` or implicit output references. Outputs wire modules together: `output storageId string = storageModule.outputs.id` lets a downstream module consume the resource without hardcoded IDs.

Scoping is explicit — `targetScope = 'subscription'` at the file top shifts deployment from resource group to subscription level, enabling management-group-wide policy assignments or role definitions in the same pipeline. Bicep's `existing` keyword references pre-existing resources (`resource vnet 'Microsoft.Network/virtualNetworks@2023-04-01' existing = { name: vnetName }`) without importing them into state, avoiding accidental deletes.$escape$,
  $escape$targetScope = 'resourceGroup'

@allowed(['Standard_LRS', 'Premium_LRS'])
param storageSku string = 'Standard_LRS'
param location string = resourceGroup().location

module storage './modules/storage.bicep' = {
  name: 'storageDeployment'
  params: {
    sku: storageSku
    location: location
  }
}

output storageAccountId string = storage.outputs.id$escape$,
  $escape$bash$escape$,
