INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b7acbbfe-39e4-4755-aa68-ddd5aea82169',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bicep Dev's Guide to AWS CDK: Constructs, Stacks, and L1/L2/L3 Abstractions$escape$,
  $escape$Bicep developers think in `resource` declarations and modules. AWS CDK maps to this mental model through a three-tier Construct hierarchy.

L1 Constructs (`CfnBucket`, `CfnFunction`) are 1:1 CloudFormation resource mappings — the equivalent of a raw Bicep `resource` block with every property explicit. No defaults, full fidelity to the underlying schema.

L2 Constructs (`Bucket`, `Function`) are what Bicep modules aspire to be: opinionated wrappers that apply secure defaults (server-side encryption on, public access blocked) and expose ergonomic APIs. Where Bicep forces you to manually author `roleAssignment` resources and wire `dependsOn`, L2s internalize IAM through grant methods like `grantRead()` — the dependency graph is implicit.

L3 Constructs (`ApplicationLoadBalancedFargateService`) are pattern libraries — equivalent to a Bicep module registry entry that provisions an entire architecture: VPC, ECS cluster, ALB, and target group in a single instantiation.

A Stack is CDK's deployment unit, mirroring a Bicep file paired with `az deployment group create`. The key difference: stacks are composable in code — pass cross-stack outputs as constructor props instead of chaining parameter files.$escape$,
  $escape$import * as cdk from 'aws-cdk-lib';
import * as s3 from 'aws-cdk-lib/aws-s3';
import * as iam from 'aws-cdk-lib/aws-iam';

class StorageStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string) {
    super(scope, id);

    // L1: raw CloudFormation — like a Bicep `resource` block, every prop explicit
    new s3.CfnBucket(this, 'RawBucket', { versioningConfiguration: { status: 'Enabled' } });

    // L2: encryption + public-access block applied by default
    const bucket = new s3.Bucket(this, 'ManagedBucket', { versioned: true });

    // L2 IAM wiring — replaces manual roleAssignment resources in Bicep
    bucket.grantRead(new iam.ArnPrincipal('arn:aws:iam::123456789012:role/Reader'));
  }
}

new StorageStack(new cdk.App(), 'StorageStack');$escape$,
