INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bbff01d1-7f87-4231-9d88-d707f6c801d2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bicep Drift Detection — What-If, Complete Mode, and Reconciliation$escape$,
  $escape$Bicep deployments default to `--mode Incremental`, so ARM only touches resources declared in your template — manual portal or CLI changes accumulate silently. This is drift: live state diverging from your `.bicep` source of truth.

Run `az deployment group what-if` to surface it. This invokes ARM's `/whatIf` endpoint, diffing your compiled ARM JSON against the live resource graph. Output is categorized as `Create`, `Modify`, `Delete`, or `NoChange` — no resources are touched during this phase.

To reconcile, redeploy with `--mode Complete`. ARM treats your Bicep template as the sole authority: any resource in the resource group absent from the template is deleted. Scope it tightly — use `targetScope = 'resourceGroup'` in your Bicep file and pin `--resource-group` explicitly.

For stricter drift prevention, `az stack group create` (Azure Deployment Stacks) adds deny assignments that block out-of-band changes at the ARM layer before drift can occur. Stacks also expose `--action-on-unmanage deleteAll` to automate cleanup of orphaned resources on teardown, giving you Terraform-style lifecycle control natively in Bicep.$escape$,
  $escape$# 1. Detect drift — no resources are modified
az deployment group what-if \
  --resource-group myRG \
  --template-file main.bicep \
  --parameters @params.json

# 2. Reconcile — Complete mode deletes any resource
#    in myRG that is NOT declared in main.bicep
az deployment group create \
  --resource-group myRG \
  --template-file main.bicep \
  --parameters @params.json \
  --mode Complete

# 3. Prevent drift at the source with Deployment Stacks
az stack group create \
  --name myStack \
  --resource-group myRG \
  --template-file main.bicep \
  --action-on-unmanage deleteAll$escape$,
  $escape$bash$escape$,
